sql:
SELECT * 
FROM biological_processes 
WHERE process_id > 100;

external_knowledge:
- 'Pioneers' refers to the top researchers in terms of gene interactions; 
- 'Heart of scientific exploration' metaphorically represents the importance of gene interactions in biological research;
- 'Biological process category' refers to the different types of biological processes classified within the database.

sql:
SELECT category, COUNT(*) AS num_processes
FROM biological_processes
GROUP BY category;

SELECT process_name, category, go_id, description
FROM biological_processes
WHERE parent_process_id IS NULL;

SELECT COUNT(process_id) AS NumOfProcessesWithGoId 
FROM biological_processes
WHERE go_id IS NOT NULL;

SELECT AVG(confidence_score) AS Average_Confidence_Score
FROM gene_interactions
WHERE interaction_type = 'activation';

SELECT process_id, fold_change, p_value, effect_size
FROM gene_expression_data
WHERE gene = 'Desired Gene Here';

SELECT ua.username, r.name, r.email
FROM user_accounts ua
JOIN researchers r ON ua.researcher_id = r.researcher_id;

SELECT title, creator_id
FROM data_visualizations
WHERE data_used LIKE '%A%' AND data_used LIKE '%B%';

SELECT * FROM projects WHERE project_id IN (
    SELECT project_id 
    FROM project_members 
    WHERE researcher_id = (
        SELECT researcher_id 
        FROM researchers 
        WHERE name = 'specified_researcher_name'
    ) 
    AND role <> 'Principal Investigator'
);

external_knowledge:
- Significant gene interactions refer to interactions with a confidence score above 0.95;
- Substantial expression changes are those with a fold change greater than 2.0;
- Recent visualizations are those created after January 1, 2020.

